import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly escaping user input to prevent XSS
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Output the result with properly escaped user input
        String output = "<p>Welcome, " + escapedUserInput + "</p>";

        // Output the result to a file
        try (FileWriter writer = new FileWriter("output.html")) {
            writer.write(output);
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
